const checks = [];

// 1. ore-istruttori app
try {
  const r1 = await fetch('https://istruttori.olisticzone.it/login', { signal: AbortSignal.timeout(10000) });
  if (r1.ok) {
    checks.push({ name: 'ore-istruttori', ok: true });
  } else {
    checks.push({ name: 'ore-istruttori', ok: false, error: `HTTP ${r1.status}`, dove: 'VPS → docker logs ore-istruttori' });
  }
} catch (e) {
  checks.push({ name: 'ore-istruttori', ok: false, error: e.message, dove: 'VPS → docker ps | grep ore-istruttori' });
}

// 2. mcp-dbgym
try {
  const r2 = await fetch('http://mcp-dbgym:3100/health', { signal: AbortSignal.timeout(10000) });
  if (r2.ok) {
    checks.push({ name: 'mcp-dbgym', ok: true });
  } else {
    checks.push({ name: 'mcp-dbgym', ok: false, error: `HTTP ${r2.status}`, dove: 'VPS → docker logs mcp-dbgym' });
  }
} catch (e) {
  checks.push({ name: 'mcp-dbgym', ok: false, error: e.message, dove: 'VPS → docker ps | grep mcp-dbgym' });
}

// 3. DB connection via mcp-dbgym query
try {
  const r3 = await fetch('http://mcp-dbgym:3100/api/query', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + $env.DBGYM_API_KEY },
    body: JSON.stringify({ sql: 'SELECT TOP 1 1 AS ok FROM dbgym.dbo.Prenotazioni WHERE IDAzienda = 1' }),
    signal: AbortSignal.timeout(15000)
  });
  if (r3.ok) {
    checks.push({ name: 'dbgym (SQL Server)', ok: true });
  } else {
    const body = await r3.text();
    checks.push({ name: 'dbgym (SQL Server)', ok: false, error: body.slice(0, 100), dove: 'Controllare connessione SQL Server Windows 2012 — potrebbe essere spento o irraggiungibile' });
  }
} catch (e) {
  checks.push({ name: 'dbgym (SQL Server)', ok: false, error: e.message, dove: 'Server Windows 2012 potrebbe essere offline. Controllare VPN/rete locale.' });
}

const allOk = checks.every(c => c.ok);
const errors = checks.filter(c => !c.ok);

let text;
if (allOk) {
  text = 'Gestionale ore istruttori tutto ok';
} else {
  text = 'ATTENZIONE — Problemi rilevati:\n';
  for (const e of errors) {
    text += `\n${e.name}: ${e.error}\nDove guardare: ${e.dove}\n`;
  }
}

return [{ json: { text, allOk } }];
